export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "銀色外殼貼在掌心。血正沿著她的生命線往下流。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)放下。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這兩個字是廣播教的。不是她想的。她腦子裡的第一個念頭還是「壓住傷口」。千田的呼吸已經淺到她得湊近才能確認——胸口在動，很慢，慢到像是在跟什麼東西商量。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "第七車乘客，請立即放下手中的尖銳物。雙手離開物品，退後兩步。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第四次。語調和前三次一模一樣。沒有升高，沒有催促，沒有任何一個人會在說「請」的時候附帶的禮貌起伏。它只是把同樣的音節再鋪一層，像在覆蓋什麼。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)我放下，誰壓他的傷口？", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說出口。她知道對著通話孔喊這句話沒有用——剛才她喊過「有人受傷」，系統回給她的是「放下尖銳物」。它不接她的話。它只輸出它自己的指令。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的右手還壓在千田肋下。掌心一片濕熱，溫度正在往下走——從剛才的燙變成現在的溫，再過一會兒就會變成涼。她不敢想「涼」代表什麼。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的手從座椅邊緣滑落了。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是突然的。是慢慢鬆開、慢慢滑下去的那種。他的手指先離開扶手，然後是掌心，最後整隻手垂到身側，指節碰到了座椅下方的金屬支架，發出一聲很輕的響。他的眼睛是睜著的，但沒有在看任何東西。瞳孔對著天花板的白光，像兩顆被沖洗過的玻璃珠。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他沒有在看。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她叫了他一聲。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "千田先生。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有回應。連呼吸的幅度都沒有變化。她不確定他聽不聽得到。她不確定他還在不在。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "請放下尖銳物。退後兩步。雙手可見。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又來了。她低頭看了一眼左手——那塊銀色外殼被她的掌心捂出一點溫度，翹起的三角邊抵著指根，在冷光下反著一道亮線。她的手指已經握了太久，關節是僵的，鬆開的時候需要刻意掰。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)不能丟。丟了會滑到座椅底下。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想過把它扔遠。但扔這個動作本身就不對——監視器會看見她把一個沾血的東西丟出去，那看起來像什麼？她想過把它塞進口袋。更不對。藏。她想過繼續握著。但廣播不會停，門不會開，救護不會進來。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她慢慢蹲下來。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右手沒有離開千田的傷口——她做不到同時放手。她用左手把外殼從掌心剝開，一點一點，像在拆一個她不敢弄壞的東西。手指鬆開的時候，金屬表面和她的皮膚之間拉出一絲黏膩的阻力。血已經把兩者黏在一起了。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把外殼放在地板上。千田座椅前方的地板，空曠、可見、監視器照得到的位置。不是塞到座椅底下，不是推到角落。放在那裡，讓它被看見。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "放手的那一刻，她看見了。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外殼翻了一面，正面朝上。破裂的三角邊在地板的冷光下像一個被掰開的殼——金屬邊緣不整齊，是從某個東西上面被強行撬下來的。內側有一排金色接點，整整滙齊，像記憶卡或電子模組的針腳。被撬開的缺口在殼體側面，邊緣有工具留下的壓痕。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她看見血跡下面的東西。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外殼表面沾著血，血從她掌心轉印上去的，半乾未乾。在血層薄的地方——靠近撬開缺口的那一側——金屬面上露出一個刻痕。像「T」。旁邊還有一道斜的痕跡，像「7」。不是印刷字體，是刻上去的，很淺，如果不是血剛好沒蓋住，她不會注意到。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)T……7。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有時間想這兩個字代表什麼。她只來得及把它記住。像拍照一樣——快門按下去，畫面存進來，之後再想是什麼意思。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "請退後兩步。雙手可見。遠離物品。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的右手還壓在千田身上。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)退後。退後就是放開他。", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她感覺得到千田的體溫在往下走。隔著外套，那股熱正在變成不對勁的涼。她的手掌貼著他的肋下，血還在往外滲，但速度比剛才慢了——不是因為止住了，是因為越來越沒有東西可以滲了。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她鬆開了右手。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是決定。是身體比腦子先服從了。她的手離開千田的傷口，在半空中停了一秒——掌心朝上，全是血，血從掌紋的溝壑裡往下走，滴在地板上，聲音很輕。然後她退後一步。兩步。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田沒有因為她鬆手而產生任何反應。他的身體維持著前傾的姿勢，靠在座椅和窗戶的夾角裡。血從外套內側繼續往外走，沿著座位縫隙往下滲，在塑料椅面上積成一小灘。那灘血的邊緣已經開始發暗了。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)我放下了。我退後了。現在可以來人了嗎？", background: Background.Chapter_3_Ch3_Act1_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她舉起雙手。掌心朝外，手指張開，讓監視器看見她手裡什麼都沒有。血從她的手腕沿著小臂內側往下走，在袖口內側洇開一小片深色。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車門沒有開。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "廣播也停了。沒有第五次指令，沒有「謝謝配合」，沒有「門即將開啟」。只有車廂的空調聲和千田越來越淺的呼吸——如果那還算呼吸的話。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在車廂中間，雙手舉著，掌心朝外，像在向一個看不見的東西投降。她腳邊的地板上，銀色外殼躺在冷光裡，破邊朝上，金色接點朝上，血下面的 T 和 7 朝上。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有人進來。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她等了十秒。二十秒。她數了。她不知道自己為什麼在數——查核員的習慣，混亂裡唯一能抓住的東西就是時間。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後車廂外的月台傳來了腳步聲。很多雙。快的、重的、帶著設備碰撞聲的腳步。有人在車門外面喊了一句什麼，聽不清楚，像是對講機的聲音。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車門上的指示燈從紅色跳成了綠色。", background: Background.Chapter_3_Ch3_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門開了。", background: Background.Chapter_3_Ch3_Act1_S0 },
];
